"use client";

import { useEffect, useState } from "react";
import { CredentialsModal } from "@/components/CredentialsModal";
import {
  clearCredentials,
  getAccessToken,
  loadCredentials,
  saveCredentials,
} from "@/lib/sentinel/auth";
import { fetchFrame } from "@/lib/sentinel/process";
import type { Bbox, Credentials } from "@/types/sentinel";

const DUESSELDORF_MEDIENHAFEN: Bbox = [6.72, 51.21, 6.78, 51.24];
const TEST_FROM = "2024-06-01T00:00:00Z";
const TEST_TO = "2024-08-31T23:59:59Z";

type Stage =
  | { kind: "idle" }
  | { kind: "authing" }
  | { kind: "authed"; token: string }
  | { kind: "fetching"; token: string }
  | { kind: "ok"; token: string; imageUrl: string }
  | { kind: "error"; message: string };

interface EnvFlags {
  sab: boolean;
  coi: boolean;
  secure: boolean;
}

export default function Home() {
  const [creds, setCreds] = useState<Credentials | null>(null);
  const [credsLoaded, setCredsLoaded] = useState(false);
  const [showModal, setShowModal] = useState(false);
  const [stage, setStage] = useState<Stage>({ kind: "idle" });
  const [env, setEnv] = useState<EnvFlags>({ sab: false, coi: false, secure: false });

  useEffect(() => {
    const c = loadCredentials();
    setCreds(c);
    setCredsLoaded(true);
    if (!c) setShowModal(true);

    setEnv({
      sab: typeof SharedArrayBuffer === "function",
      coi:
        (window as unknown as { crossOriginIsolated?: boolean }).crossOriginIsolated === true,
      secure: window.isSecureContext,
    });
  }, []);

  function handleSave(c: Credentials) {
    saveCredentials(c);
    setCreds(c);
    setShowModal(false);
    setStage({ kind: "idle" });
  }

  function handleReset() {
    clearCredentials();
    setCreds(null);
    setStage({ kind: "idle" });
    setShowModal(true);
  }

  async function runAuth() {
    if (!creds) return;
    setStage({ kind: "authing" });
    try {
      const token = await getAccessToken(creds);
      setStage({ kind: "authed", token });
    } catch (err) {
      setStage({ kind: "error", message: err instanceof Error ? err.message : String(err) });
    }
  }

  async function runFrame() {
    if (!creds) return;
    setStage({ kind: "authing" });
    try {
      const token = await getAccessToken(creds);
      setStage({ kind: "fetching", token });
      const blob = await fetchFrame({
        bbox: DUESSELDORF_MEDIENHAFEN,
        from: TEST_FROM,
        to: TEST_TO,
        width: 512,
        height: 512,
        accessToken: token,
      });
      const imageUrl = URL.createObjectURL(blob);
      setStage({ kind: "ok", token, imageUrl });
    } catch (err) {
      setStage({ kind: "error", message: err instanceof Error ? err.message : String(err) });
    }
  }

  return (
    <main className="mx-auto w-full max-w-4xl flex-1 px-4 py-10 sm:px-6 lg:px-8">
      <header className="mb-8">
        <h1 className="text-3xl font-semibold tracking-tight">Sentipede</h1>
        <p className="mt-2 text-neutral-400">
          Client-side satellite timelapse generator — Sentinel-2 via Copernicus Data Space.
        </p>
      </header>

      <section className="mb-8 rounded-2xl border border-neutral-800 bg-neutral-900 p-5">
        <h2 className="mb-3 text-sm font-semibold uppercase tracking-wider text-neutral-400">
          Environment
        </h2>
        <dl className="grid grid-cols-2 gap-3 text-sm sm:grid-cols-4">
          <StatusChip label="SharedArrayBuffer" ok={env.sab} />
          <StatusChip label="crossOriginIsolated" ok={env.coi} />
          <StatusChip label="Credentials" ok={creds !== null && credsLoaded} />
          <StatusChip label="Secure context" ok={env.secure} />
        </dl>
      </section>

      <section className="mb-8 rounded-2xl border border-neutral-800 bg-neutral-900 p-5">
        <div className="mb-4 flex items-center justify-between">
          <h2 className="text-sm font-semibold uppercase tracking-wider text-neutral-400">
            Connection test
          </h2>
          <div className="flex gap-2">
            {creds && (
              <button
                type="button"
                onClick={handleReset}
                className="rounded-lg border border-neutral-700 px-3 py-1.5 text-xs text-neutral-400 hover:text-neutral-200"
              >
                Clear credentials
              </button>
            )}
            <button
              type="button"
              onClick={() => setShowModal(true)}
              className="rounded-lg border border-neutral-700 px-3 py-1.5 text-xs text-neutral-400 hover:text-neutral-200"
            >
              {creds ? "Edit credentials" : "Add credentials"}
            </button>
          </div>
        </div>

        <div className="flex flex-wrap gap-2">
          <button
            type="button"
            onClick={runAuth}
            disabled={!creds || stage.kind === "authing"}
            className="rounded-lg bg-sky-500 px-4 py-2 text-sm font-medium text-black hover:bg-sky-400 disabled:cursor-not-allowed disabled:bg-neutral-700 disabled:text-neutral-400"
          >
            {stage.kind === "authing" ? "Requesting token…" : "1. Get OAuth token"}
          </button>
          <button
            type="button"
            onClick={runFrame}
            disabled={!creds || stage.kind === "authing" || stage.kind === "fetching"}
            className="rounded-lg border border-neutral-700 bg-neutral-800 px-4 py-2 text-sm font-medium hover:bg-neutral-700 disabled:cursor-not-allowed disabled:opacity-50"
          >
            {stage.kind === "fetching" ? "Fetching frame…" : "2. Fetch Düsseldorf frame"}
          </button>
        </div>

        <div className="mt-4 text-sm">
          {stage.kind === "authed" && (
            <p className="text-emerald-400">
              ✓ OAuth succeeded. Token prefix:{" "}
              <span className="font-mono text-xs">{stage.token.slice(0, 24)}…</span>
            </p>
          )}
          {stage.kind === "error" && (
            <pre className="whitespace-pre-wrap rounded-lg border border-red-900/60 bg-red-950/40 p-3 text-xs text-red-300">
              {stage.message}
            </pre>
          )}
          {stage.kind === "ok" && (
            <div className="space-y-2">
              <p className="text-emerald-400">
                ✓ Process API returned a PNG — CORS works from this origin.
              </p>
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img
                src={stage.imageUrl}
                alt="Düsseldorf Medienhafen"
                className="rounded-lg border border-neutral-800"
                width={512}
                height={512}
              />
            </div>
          )}
        </div>
      </section>

      {showModal && (
        <CredentialsModal
          initial={creds}
          onSave={handleSave}
          onClose={creds ? () => setShowModal(false) : undefined}
        />
      )}
    </main>
  );
}

function StatusChip({ label, ok }: { label: string; ok: boolean }) {
  return (
    <div className="flex items-center gap-2 rounded-lg border border-neutral-800 bg-neutral-950 px-3 py-2">
      <span
        className={`h-2 w-2 rounded-full ${ok ? "bg-emerald-400" : "bg-neutral-600"}`}
        aria-hidden
      />
      <span className={`text-xs ${ok ? "text-neutral-200" : "text-neutral-500"}`}>{label}</span>
    </div>
  );
}
